#include "influxdb.h"
#include <WiFi.h>
#include <InfluxDbClient.h>
static InfluxDBClient*_client=nullptr;
static Point*_point=nullptr;
void influx_setup(const char*url,const char*org,const char*bkt,const char*tok){_client=new InfluxDBClient(url,org,bkt,tok);if(_client->validateConnection())Serial.println("[influx] OK");else Serial.println("[influx] Fail!");}
void influx_add_field(const char*m,const char*f,float v){if(_point)delete _point;_point=new Point(m);_point->addField(f,v);}
bool influx_write(){if(!_client||!_point)return false;bool ok=_client->writePoint(*_point);delete _point;_point=nullptr;return ok;}
